request.query:
prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT DISTINCT ?model ?modelId ?edgeCount ?hasCycle WHERE {
  ?model a bboExt:Model ;
         tai:originalId ?modelId .
  FILTER(?modelId = "0b21c69687b64d8886fb7cc5dc56ff6c")

  ?defs tai:belongsTo ?model .
  ?choreo tai:belongsTo ?defs .

  {
    SELECT (COUNT(DISTINCT ?sf) AS ?edgeCount) WHERE {
      ?sf a bbo:SequenceFlow ;
          tai:belongsTo ?choreo .
    }
  }

  {
    # cycle witness: a node reachable from itself via one-or-more outgoing sequence flows
    SELECT (IF(BOUND(?self), true, false) AS ?hasCycle) WHERE {
      SELECT DISTINCT ?self WHERE {
        ?self ((^bbo:has_sourceRef)/bbo:has_targetRef)+ ?self .
        ?self tai:belongsTo ?choreo .
      }
      LIMIT 1
    }
  }
}
LIMIT 25
